const relativeMinutesLabel = (value?: string | null) => {
  if (!value) return "Never";
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return formatMoment(value);
  const diffMinutes = Math.max(0, Math.round((Date.now() - parsed.getTime()) / (60 * 1000)));
  if (diffMinutes < 1) return "Just now";
  if (diffMinutes < 60) return `${diffMinutes}m ago`;
  const diffHours = Math.round(diffMinutes / 60);
  if (diffHours < 24) return `${diffHours}h ago`;
  const diffDays = Math.round(diffHours / 24);
  return `${diffDays}d ago`;
};
const getWaybillStatusMoment = (waybill: WaybillRecord, movements: StockMovement[]) => {
  if (waybill.status === "In Transit") {
    return waybill.createdAt;
  }
  if (waybill.status === "Cancelled") {
    return undefined;
  }

  const movementType =
    waybill.status === "Received" || waybill.status === "Returned"
      ? "Waybill In"
      : "Correction";
  const matchingMovement = movements.find((movement) => movement.waybillId === waybill.id && movement.type === movementType);
  return matchingMovement?.createdAt ?? matchingMovement?.date ?? (waybill.status === "Received" && waybill.dateReceived ? waybill.createdAt : undefined);
};

const scheduleDateForRange = (range: ScheduleRange, customDate?: string) => {
  if (range === "Custom" && customDate) return customDate;
  const date = new Date();
  date.setDate(date.getDate() + (range === "Today" ? 0 : range === "Tomorrow" ? 1 : 2));
  return formatDateKey(date);
};

const isInPeriod = (dateKey: string | undefined, activePeriod: Period, range: DateRange) => {
  const value = normalizeDateKey(dateKey);
  const now = new Date();
  const today = formatDateKey(now);
  const weekStart = new Date(now);
  weekStart.setDate(now.getDate() - now.getDay());

  if (activePeriod === "Custom") {
    return Boolean(range.start && range.end && value >= range.start && value <= range.end);
  }

  if (activePeriod === "Today") {
    return value === today;
  }

  if (activePeriod === "This Week") {
    return value >= formatDateKey(weekStart) && value <= today;
  }

  if (activePeriod === "This Month") {
    return value.slice(0, 7) === today.slice(0, 7);
  }

  return value.slice(0, 4) === today.slice(0, 4);
};

const periodBoundsForQuery = (activePeriod: Period, range: DateRange) => {
  const now = new Date();
  const today = formatDateKey(now);
  const weekStart = new Date(now);
  weekStart.setDate(now.getDate() - now.getDay());

  if (activePeriod === "Custom") {
    return range.start && range.end ? { dateFrom: range.start, dateTo: range.end } : null;
  }

  if (activePeriod === "Today") {
    return { dateFrom: today, dateTo: today };
  }

  if (activePeriod === "This Week") {
    return { dateFrom: formatDateKey(weekStart), dateTo: today };
  }

  if (activePeriod === "This Month") {
    return { dateFrom: `${today.slice(0, 7)}-01`, dateTo: today };
  }

  return { dateFrom: `${today.slice(0, 4)}-01-01`, dateTo: today };
};

const daysInPeriodSoFar = (activePeriod: Period, range: DateRange) => {
  const now = new Date();
  if (activePeriod === "Custom" && range.start && range.end) {
    const start = new Date(`${range.start}T00:00:00`);
    const end = new Date(`${range.end}T00:00:00`);
    // Cap end to today so future dates don't deflate the daily average
    const capped = end.getTime() > now.getTime() ? now : end;
    return Math.max(1, Math.round((capped.getTime() - start.getTime()) / 86_400_000) + 1);
  }

  if (activePeriod === "Today") {
    return 1;
  }

  if (activePeriod === "This Week") {
    return now.getDay() + 1;
  }

  if (activePeriod === "This Month") {
    return now.getDate();
  }

  const yearStart = new Date(now.getFullYear(), 0, 1);
  return Math.max(1, Math.round((now.getTime() - yearStart.getTime()) / 86_400_000) + 1);
};

const fulfillmentDaysForOrder = (order: TrackedOrder) => {
  const created = new Date(`${orderCreatedKey(order)}T00:00:00`);
  const delivered = new Date(`${orderDeliveredKey(order) || orderCreatedKey(order)}T00:00:00`);
  if (Number.isNaN(created.getTime()) || Number.isNaN(delivered.getTime())) {
    return 0;
  }
  return Math.max(0, Math.round((delivered.getTime() - created.getTime()) / 86_400_000));
};

const explicitPeriodRange = (activePeriod: Period, range: DateRange, previous = false): DateRange => {
  const now = new Date();
  const today = formatDateKey(now);

  if (activePeriod === "Custom" && range.start && range.end) {
    if (!previous) {
      return range;
    }

    const start = new Date(`${range.start}T00:00:00`);
    const end = new Date(`${range.end}T00:00:00`);
    const length = Math.max(1, Math.round((end.getTime() - start.getTime()) / 86_400_000) + 1);
    const previousEnd = new Date(start);
    previousEnd.setDate(start.getDate() - 1);
    const previousStart = new Date(previousEnd);
    previousStart.setDate(previousEnd.getDate() - length + 1);
    return { start: formatDateKey(previousStart), end: formatDateKey(previousEnd) };
  }

  if (activePeriod === "Today") {
    if (!previous) {
      return { start: today, end: today };
    }
    const date = new Date(now);
    date.setDate(now.getDate() - 1);
    const key = formatDateKey(date);
    return { start: key, end: key };
  }

  if (activePeriod === "This Week") {
    const start = new Date(now);
    start.setDate(now.getDate() - now.getDay());
    const end = new Date(now);
    if (previous) {
      start.setDate(start.getDate() - 7);
      end.setDate(end.getDate() - 7);
    }
    return { start: formatDateKey(start), end: formatDateKey(end) };
  }

  if (activePeriod === "This Month") {
    if (!previous) {
      return { start: formatDateKey(new Date(now.getFullYear(), now.getMonth(), 1)), end: today };
    }
    const previousMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1);
    const lastDay = new Date(now.getFullYear(), now.getMonth(), 0).getDate();
    return {
      start: formatDateKey(previousMonth),
      end: formatDateKey(new Date(previousMonth.getFullYear(), previousMonth.getMonth(), Math.min(now.getDate(), lastDay)))
    };
  }

  if (!previous) {
    return { start: formatDateKey(new Date(now.getFullYear(), 0, 1)), end: today };
  }

  return {
    start: formatDateKey(new Date(now.getFullYear() - 1, 0, 1)),
    end: formatDateKey(new Date(now.getFullYear() - 1, now.getMonth(), now.getDate()))
  };
};

const isInExplicitRange = (dateKey: string | undefined, range: DateRange) => {
  const value = normalizeDateKey(dateKey);
  return Boolean(range.start && range.end && value >= range.start && value <= range.end);
};

const percentChange = (current: number, previous: number) => {
  if (previous === 0) {
    // No prior baseline: 0→0 is flat, anything→nonzero is "New" (no finite %).
    return current === 0 ? 0 : Number.POSITIVE_INFINITY;
  }
  return Math.round(((current - previous) / previous) * 1000) / 10;
};

const formatTrend = (change: number) => {
  if (!Number.isFinite(change)) return "New";
  return `${change >= 0 ? "+" : ""}${change.toFixed(1)}%`;
};

const formatOrderCreatedAt = (order: Pick<TrackedOrder, "createdAt" | "date">) =>
  formatMoment(order.createdAt) || displayDateFromKey(order.date);
const orderCreatedKey = (order: TrackedOrder) => normalizeDateKey(order.createdAt ?? order.date);
const orderDeliveredKey = (order: TrackedOrder) =>
  order.deliveredDate ? normalizeDateKey(order.deliveredDate) : (order.status ?? "New") === "Delivered" ? orderCreatedKey(order) : "";

const timeSinceCreated = (order: TrackedOrder): string => {
  const created = new Date(order.createdAt ?? order.date);
  if (Number.isNaN(created.getTime())) return "—";
  const diffMs = Date.now() - created.getTime();
  const mins = Math.max(0, Math.floor(diffMs / 60_000));
  if (mins < 60) return `${mins}m`;
  const hours = mins / 60;
  if (hours < 24) return `${hours.toFixed(1)}h`;
  const days = Math.floor(hours / 24);
  return `${days}d`;
};

const responseTimeColor = (order: TrackedOrder, status: string): { label: string; cls: string } => {
  const terminal = status === "Delivered" || status === "Cancelled";
  const created = new Date(order.createdAt ?? order.date);
  if (Number.isNaN(created.getTime())) return { label: "—", cls: "text-gray-400" };
  if (terminal) return { label: "—", cls: "text-gray-300" };
  const diffMs = Date.now() - created.getTime();
  const mins = Math.max(0, Math.floor(diffMs / 60_000));
  const hours = mins / 60;
  const label = mins < 60 ? `${mins}m` : hours < 24 ? `${hours.toFixed(1)}h` : `${Math.floor(hours / 24)}d`;
  if (mins < 60) return { label, cls: "text-emerald-600 bg-emerald-50" };
  if (hours <= 4) return { label, cls: "text-gray-500 bg-gray-100" };
  if (hours < 24) return { label, cls: "text-amber-700 bg-amber-50" };
  return { label, cls: "text-red-600 bg-red-50" };
};

const parseExpenseDateKey = (value: string) => {
  if (/^\d{4}-\d{2}-\d{2}$/.test(value)) {
    return value;
  }

  const parts = value.split("/");
  if (parts.length === 3) {
    const [day, month, year] = parts;
    return `${year}-${month.padStart(2, "0")}-${day.padStart(2, "0")}`;
  }

  return normalizeDateKey(value);
};

const makeCartId = () => `CART-${Math.floor(100000 + Math.random() * 900000)}`;
const makeAgentId = () => `agent-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`;
const makeExpenseId = () => `EXP-${Math.floor(100000 + Math.random() * 900000)}`;
