const normalisePackageCompanion = (companion: Partial<PackageCompanion>): PackageCompanion => ({
  companionId: companion.companionId || makeCompanionId(),
  productId: companion.productId || "",
  packageId: companion.packageId || undefined,
  quantity: Math.max(1, Number(companion.quantity) || 1),
  pricingMode: companion.pricingMode === "fixed" || companion.pricingMode === "use_product_price" ? companion.pricingMode : "free",
  fixedPrice: typeof companion.fixedPrice === "number" ? companion.fixedPrice : undefined,
  stateFilterMode: companion.stateFilterMode === "block"
    ? "block"
    : companion.stateFilterMode === "allow" && Array.isArray(companion.stateRestrictions) && companion.stateRestrictions.length > 0
      ? "allow"
      : companion.stateFilterMode === "all"
        ? "all"
        : "all",
  stateRestrictions: Array.isArray(companion.stateRestrictions) ? companion.stateRestrictions : [],
  autoInclude: Boolean(companion.autoInclude),
  placement: companion.placement === "upsell" ? "upsell" : "inline",
  pitch: companion.pitch ?? "",
  badgeText: companion.badgeText ?? "",
  headline: companion.headline ?? "",
  ctaText: companion.ctaText ?? "",
  declineText: companion.declineText ?? "",
  imageUrl: companion.imageUrl ?? "",
  videoUrl: companion.videoUrl ?? "",
  embedHtml: companion.embedHtml ?? "",
  priority: typeof companion.priority === "number" ? companion.priority : 0,
  displayMode: companion.displayMode === "card" ? "card" : "compact"
});
const clonePackageCompanions = (companions: PackageCompanion[]) =>
  companions.map((companion) =>
    normalisePackageCompanion({
      ...companion,
      companionId: makeCompanionId()
    })
  );
const normalisePackageComponent = (component: Partial<PackageComponent>): PackageComponent => ({
  componentId: component.componentId || `pkg-comp-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`,
  productId: component.productId || "",
  quantity: Math.max(1, Number(component.quantity) || 1),
  isFreeGift: Boolean(component.isFreeGift),
  note: component.note ?? ""
});
const companionMatchesState = (
  companion: Pick<PackageCompanion, "stateRestrictions" | "stateFilterMode">,
  state: string
) => {
  const mode = companion.stateFilterMode ?? "all";
  if (mode === "all") return true;
  if (companion.stateRestrictions.length === 0) return mode === "block";
  if (!state) return false;
  const normalizedState = normalizeStateName(state);
  const matches = companion.stateRestrictions.map(normalizeStateName).includes(normalizedState);
  return mode === "block" ? !matches : matches;
};
const companionConfiguredTotal = (
  companion: Pick<PackageCompanion, "pricingMode" | "fixedPrice" | "quantity">,
  standardPrice: number
) => {
  const normalizedQuantity = Math.max(1, Number(companion.quantity) || 1);
  if (companion.pricingMode === "free") return 0;
  if (companion.pricingMode === "fixed") return Math.max(0, Number(companion.fixedPrice ?? 0));
  return standardPrice * normalizedQuantity;
};
const formatBundleUnitLabel = (quantity: number) => `${quantity}${quantity === 1 ? "pc" : "pcs"}`;
const summarizePackageComponents = (
  components: PackageComponent[] | undefined,
  products: Pick<Product, "id" | "name">[]
) => {
  if (!components || components.length === 0) return "";
  return components
    .filter((component) => component.productId)
    .map((component) => {
      const productName = products.find((product) => product.id === component.productId)?.name || "Item";
      const qtyLabel = formatBundleUnitLabel(component.quantity);
      return component.isFreeGift
        ? `FREE ${qtyLabel} ${productName}`
        : `${qtyLabel} ${productName}`;
    })
    .join(" + ");
};
const packageDescriptionSuggestion = (
  components: PackageComponent[] | undefined,
  products: Pick<Product, "id" | "name">[],
  includeFreeDelivery = false
) => {
  const summary = summarizePackageComponents(components, products);
  if (!summary) {
    return includeFreeDelivery ? "Free delivery included" : "";
  }
  return includeFreeDelivery ? `${summary} · Free delivery included` : summary;
};
const scalePackageNameForMultiplier = (name: string, multiplier: number) => {
  const trimmed = name.trim();
  if (!trimmed) return `x${multiplier} Bundle`;
  const setMatch = trimmed.match(/^(\d+)\s+Set(s)?$/i);
  if (setMatch) {
    const nextQty = Math.max(1, Number(setMatch[1] || 1) * multiplier);
    return `${nextQty} Set${nextQty === 1 ? "" : "s"}`;
  }
  const xMatch = trimmed.match(/x(\d+)/i);
  if (xMatch) {
    const nextQty = Math.max(1, Number(xMatch[1] || 1) * multiplier);
    return trimmed.replace(/x\d+/i, `x${nextQty}`);
  }
  return `${trimmed} x${multiplier}`;
};
const scalePackageComponents = (components: PackageComponent[] | undefined, multiplier: number) =>
  (components ?? []).map((component) =>
    normalisePackageComponent({
      ...component,
      componentId: `pkg-comp-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`,
      quantity: Math.max(1, component.quantity * multiplier)
    })
  );
const isTemporaryAgentId = (id: string) => id.startsWith("agent-");
const isTemporaryTeamId = (id: string) => id.startsWith("team-");
const isTemporaryPayrollRunId = (id: string) => id.startsWith("PAY-");
const isTemporaryUserId = (id: string) => id.startsWith("rep-") || /^\d{13,}-/.test(id);

const normalizeOrderNote = (value: unknown): OrderNote | null => {
  if (!value || typeof value !== "object") {
    return null;
  }
  const record = value as Record<string, unknown>;
  const text = typeof record.text === "string" ? record.text.trim() : "";
  if (!text) {
    return null;
  }
  const followUpDate = typeof record.followUpDate === "string" && isDateValue(record.followUpDate)
    ? record.followUpDate
    : undefined;
  const followUpAt = typeof record.followUpAt === "string" && record.followUpAt
    ? record.followUpAt
    : undefined;
  return {
    id: typeof record.id === "string" && record.id ? record.id : makeNoteId(),
    text,
    by: typeof record.by === "string" && record.by ? record.by : "System",
    date: typeof record.date === "string" && record.date ? record.date : nowIso(),
    followUpDate: followUpDate ?? (followUpAt ? normalizeDateKey(followUpAt) : undefined),
    followUpAt
  };
};
const normalizeOrderNotes = (value: unknown): OrderNote[] =>
  Array.isArray(value)
    ? value
        .map((entry) => normalizeOrderNote(entry))
        .filter((entry): entry is OrderNote => Boolean(entry))
    : [];
const parseLegacyOrderMetadata = (value: unknown) => {
  if (!value) {
    return {} as { scheduledAt?: string; timelineNotes?: unknown[] };
  }
  if (typeof value === "object" && !Array.isArray(value)) {
    const record = value as Record<string, unknown>;
    return {
      scheduledAt: typeof record.scheduledAt === "string" ? record.scheduledAt : undefined,
      timelineNotes: Array.isArray(record.timelineNotes) ? record.timelineNotes : undefined
    };
  }
  if (typeof value !== "string" || !value.trim()) {
    return {} as { scheduledAt?: string; timelineNotes?: unknown[] };
  }
  try {
    const parsed = JSON.parse(value);
    if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
      return {} as { scheduledAt?: string; timelineNotes?: unknown[] };
    }
    const record = parsed as Record<string, unknown>;
    return {
      scheduledAt: typeof record.scheduledAt === "string" ? record.scheduledAt : undefined,
      timelineNotes: Array.isArray(record.timelineNotes) ? record.timelineNotes : undefined
    };
  } catch {
    return {} as { scheduledAt?: string; timelineNotes?: unknown[] };
  }
};
const orderNotesFor = (value: { notes?: unknown; timelineNotes?: unknown; timeline_notes?: unknown } | null | undefined): OrderNote[] => {
  const legacyMetadata = parseLegacyOrderMetadata(value?.notes);
  return normalizeOrderNotes(
    value?.timelineNotes
      ?? value?.timeline_notes
      ?? (Array.isArray(value?.notes) ? value.notes : legacyMetadata.timelineNotes)
  );
};
type PublicFormSubmissionDetails = {
  customerName?: string;
  phone?: string;
  whatsapp?: string;
  email?: string;
  address?: string;
  preferredDelivery?: string;
  confirmation?: string;
  selectedPackages?: string;
  utmSource?: string;
  utmCampaign?: string;
  utmMedium?: string;
  utmContent?: string;
  utmTerm?: string;
  referrer?: string;
};
type PublicFormSubmissionField = {
  label: string;
  value: string;
  wide?: boolean;
};
type PublicFormSubmissionSection = {
  title: string;
  rows: PublicFormSubmissionField[];
  fullWidth?: boolean;
};
const parsePublicFormSubmissionNote = (noteText: string): PublicFormSubmissionDetails => {
  const out: PublicFormSubmissionDetails = {};
  for (const rawLine of noteText.split("\n")) {
    const line = rawLine.trim();
    if (!line || /^public form submission details:?$/i.test(line)) continue;
    const colonIndex = line.indexOf(":");
    if (colonIndex < 0) continue;
    const label = line.slice(0, colonIndex).trim().toLowerCase();
    const value = line.slice(colonIndex + 1).trim();
    if (!value) continue;
    if (label === "customer name") out.customerName = value;
    else if (label === "phone") out.phone = value;
    else if (label === "whatsapp") out.whatsapp = value;
    else if (label === "email") out.email = value;
    else if (label === "address") out.address = value;
    else if (label === "preferred delivery") out.preferredDelivery = value;
    else if (label === "confirmation checkbox") out.confirmation = value;
    else if (label === "selected package(s)") out.selectedPackages = value;
    else if (label === "utm source") out.utmSource = value;
    else if (label === "utm campaign") out.utmCampaign = value;
    else if (label === "utm medium") out.utmMedium = value;
    else if (label === "utm content") out.utmContent = value;
    else if (label === "utm term") out.utmTerm = value;
    else if (label === "referrer") out.referrer = value;
  }
  return out;
};
const publicFormSubmissionDetailsFor = (order: TrackedOrder): PublicFormSubmissionDetails => {
  const publicNote = orderNotesFor(order).find((note) => typeof note.text === "string" && note.text.toLowerCase().startsWith("public form submission details:"));
  const parsed = publicNote ? parsePublicFormSubmissionNote(publicNote.text) : {};
  const formattedAddress = [order.address, order.city, order.state].filter(Boolean).join(", ");
  const quantity = Math.max(1, order.quantity ?? order.originalQuantity ?? 1);
  return {
    customerName: order.customer || parsed.customerName,
    phone: order.phone || parsed.phone,
    whatsapp: order.whatsapp || parsed.whatsapp,
    email: order.email || parsed.email,
    address: formattedAddress || parsed.address,
    preferredDelivery: order.preferredDelivery ?? order.deliveryWindow ?? parsed.preferredDelivery,
    confirmation: order.confirmationChecked != null ? (order.confirmationChecked ? "Accepted" : "Not accepted") : parsed.confirmation,
    selectedPackages: parsed.selectedPackages || `${order.packageName} (${quantity} unit${quantity === 1 ? "" : "s"}, ${formatProductMoney(order.amount, order.currency)})`,
    utmSource: order.utmSource || parsed.utmSource,
    utmCampaign: order.utmCampaign || parsed.utmCampaign,
    utmMedium: order.utmMedium || parsed.utmMedium,
    utmContent: order.utmContent || parsed.utmContent,
    utmTerm: order.utmTerm || parsed.utmTerm,
    referrer: order.referrer || parsed.referrer
  };
};
const publicFormSubmissionSectionsFor = (order: TrackedOrder): PublicFormSubmissionSection[] => {
  const details = publicFormSubmissionDetailsFor(order);
  const maybeField = (label: string, value?: string, options?: { wide?: boolean }) =>
    value && value.trim().length > 0
      ? { label, value: value.trim(), wide: options?.wide }
      : null;

  return [
    {
      title: "Customer Details",
      rows: [
        maybeField("Customer Name", details.customerName),
        maybeField("Phone", details.phone),
        maybeField("WhatsApp", details.whatsapp),
        maybeField("Email", details.email),
        maybeField("Address", details.address, { wide: true })
      ].filter(Boolean) as PublicFormSubmissionField[]
    },
    {
      title: "Order Intent",
      rows: [
        maybeField("Preferred Delivery", details.preferredDelivery),
        maybeField("Confirmation", details.confirmation),
        maybeField("Selected Package(s)", details.selectedPackages, { wide: true })
      ].filter(Boolean) as PublicFormSubmissionField[]
    },
    {
      title: "Attribution",
      fullWidth: true,
      rows: [
        maybeField("UTM Source", details.utmSource),
        maybeField("UTM Campaign", details.utmCampaign),
        maybeField("UTM Medium", details.utmMedium),
        maybeField("UTM Content", details.utmContent),
        maybeField("UTM Term", details.utmTerm),
        maybeField("Referrer", details.referrer, { wide: true })
      ].filter(Boolean) as PublicFormSubmissionField[]
    }
  ].filter((section) => section.rows.length > 0);
};
const renderPublicFormSubmissionDetails = (order: TrackedOrder) => {
  const sections = publicFormSubmissionSectionsFor(order);
  if (!sections.length) return null;

  return (
    <div className="grid grid-cols-1 xl:grid-cols-2 gap-5">
      {sections.map((section) => (
        <div
          key={section.title}
          className={`rounded-[28px] border border-gray-200 bg-white px-5 py-5 shadow-sm dark:border-slate-800/90 dark:bg-[#0a131c] dark:shadow-[0_24px_50px_rgba(2,6,23,0.34)] ${
            section.fullWidth ? "xl:col-span-2" : ""
          }`}
        >
          <p className={`m-0 mb-5 text-[17px] sm:text-[19px] font-semibold tracking-[-0.02em] ${orderTitleTextClass}`}>
            {section.title}
          </p>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-x-6 gap-y-5">
            {section.rows.map((row) => (
              <div
                key={`${section.title}-${row.label}`}
                className={row.wide ? "md:col-span-2" : ""}
              >
                <p className={`m-0 text-[11px] font-bold uppercase tracking-[0.16em] ${orderFaintTextClass}`}>
                  {row.label}
                </p>
                <p className={`m-0 mt-2 text-[16px] sm:text-[17px] font-semibold leading-7 tracking-[-0.01em] break-words whitespace-pre-wrap ${orderTitleTextClass}`}>
                  {row.value}
                </p>
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
};
const hasPublicFormSubmissionDetails = (order: TrackedOrder): boolean => {
  const details = publicFormSubmissionDetailsFor(order);
  return Object.values(details).some((value) => typeof value === "string" && value.trim().length > 0);
};
const normalizeTrackedOrder = (value: any): TrackedOrder => {
  const legacyMetadata = parseLegacyOrderMetadata(value?.notes);
  const scheduledAt = typeof value?.scheduledAt === "string" && value.scheduledAt
    ? value.scheduledAt
    : typeof value?.scheduled_at === "string" && value.scheduled_at
      ? value.scheduled_at
    : legacyMetadata.scheduledAt;
  const scheduledDate = typeof value?.scheduledDate === "string" && value.scheduledDate
    ? normalizeDateKey(value.scheduledDate)
    : typeof value?.scheduled_date === "string" && value.scheduled_date
      ? normalizeDateKey(value.scheduled_date)
    : scheduledAt
      ? normalizeDateKey(scheduledAt)
      : undefined;
  return {
    ...value,
    sourceCartId: value?.sourceCartId ?? value?.source_cart_id ?? undefined,
    createdAt: typeof value?.createdAt === "string" && value.createdAt
      ? value.createdAt
      : typeof value?.created_at === "string" && value.created_at
        ? value.created_at
        : undefined,
    updatedAt: typeof value?.updatedAt === "string" && value.updatedAt
      ? value.updatedAt
      : typeof value?.updated_at === "string" && value.updated_at
        ? value.updated_at
        : undefined,
    deliveredDate: typeof value?.deliveredDate === "string" && value.deliveredDate
      ? value.deliveredDate
      : typeof value?.delivered_date === "string" && value.delivered_date
        ? value.delivered_date
        : undefined,
    scheduledAt,
    scheduledDate,
    notes: orderNotesFor(value)
  };
};

const normalizeExpenseRecord = (value: any): ExpenseRecord => ({
  id: value.id,
  type: (value.type ?? value.category ?? "Other") as ExpenseType,
  amount: Number(value.amount ?? 0),
  currency: (value.currency ?? "NGN") as CurrencyCode,
  date: typeof value.date === "string" ? normalizeDateKey(value.date) : todayKey(),
  createdAt: typeof value.createdAt === "string" ? value.createdAt : typeof value.created_at === "string" ? value.created_at : undefined,
  productId: value.productId ?? value.product_id ?? undefined,
  productName: value.productName ?? value.product_name ?? "",
  description: value.description ?? "",
  waybillId: value.waybillId ?? value.waybill_id ?? undefined
});

