  const updateCartStatus = (cartId: string, status: Exclude<CartStatus, "All statuses">) => {
    const snapshot = abandonedCarts.find((c) => c.id === cartId);
    setAbandonedCarts((value) => value.map((cart) => (cart.id === cartId ? { ...cart, status, lastActivity: new Date().toISOString() } : cart)));
    cartsApi.update(cartId, { status }).catch((err: any) => {
      // Roll back local state so the table doesn't lie about persistence.
      if (snapshot) setAbandonedCarts((value) => value.map((cart) => (cart.id === cartId ? snapshot : cart)));
      showToast(`Failed to save status for ${cartId}: ${err?.message ?? "please retry"}.`);
    });
    showToast(`${cartId} marked ${status}.`);
  };

  const bulkUpdateCartStatus = async (status: Exclude<CartStatus, "All statuses" | "Converted">) => {
    if (selectedCartIds.size === 0) return;
    const ids = Array.from(selectedCartIds).filter((id) => {
      const cart = abandonedCarts.find((c) => c.id === id);
      return cart && cart.status !== "Converted";
    });
    // Snapshot the slice we're about to mutate so partial failures can revert
    // their own ids without disturbing the ones that succeeded.
    const snapshots = new Map(abandonedCarts.filter((c) => ids.includes(c.id)).map((c) => [c.id, c]));
    setAbandonedCarts((value) =>
      value.map((cart) =>
        selectedCartIds.has(cart.id) && cart.status !== "Converted"
          ? { ...cart, status, lastActivity: new Date().toISOString() }
          : cart
      )
    );
    setSelectedCartIds(new Set());
    const results = await Promise.allSettled(
      ids.map((id) => cartsApi.update(id, { status }))
    );
    const failedIds: string[] = [];
    results.forEach((r, i) => { if (r.status === "rejected") failedIds.push(ids[i]); });
    if (failedIds.length > 0) {
      setAbandonedCarts((value) =>
        value.map((cart) => failedIds.includes(cart.id) ? (snapshots.get(cart.id) ?? cart) : cart)
      );
      showToast(`${ids.length - failedIds.length} cart${ids.length - failedIds.length !== 1 ? "s" : ""} marked ${status}. ${failedIds.length} failed — please retry.`);
    } else {
      showToast(`${ids.length} cart${ids.length > 1 ? "s" : ""} marked ${status}.`);
    }
  };

  const deleteCartRecord = (cart: AbandonedCartRecord) => {
    const canDelete = auth.getUser()?.role === "Owner" || auth.getUser()?.role === "Admin";
    if (!canDelete) {
      showToast("Only Owner/Admin can delete abandoned carts.");
      return;
    }
    if (!window.confirm(`Delete abandoned cart ${cart.id} for ${cart.customer || "this customer"}? This cannot be undone.`)) {
      return;
    }

    const cartSnapshot = cart;
    const wasSelected = selectedCartId === cart.id;
    const wasModalOpen = wasSelected && ["cartDetails", "assignCart", "convertCart"].includes(modal ?? "");
    const routeWasFocused = hashRoute.startsWith(`#/dashboard/admin/abandoned-carts/${cart.id}`);
    setAbandonedCarts((value) => value.filter((item) => item.id !== cart.id));
    setSelectedCartIds((prev) => {
      const next = new Set(prev);
      next.delete(cart.id);
      return next;
    });
    if (wasSelected) {
      setSelectedCartId("");
    }
    if (wasModalOpen) {
      closeModal();
    }
    if (routeWasFocused) {
      syncHashRoute("#/dashboard/admin/abandoned-carts");
    }
    showToast(`${cart.id} deleted.`);

    cartsApi.delete(cart.id).catch((err: any) => {
      setAbandonedCarts((value) => [cartSnapshot, ...value.filter((item) => item.id !== cartSnapshot.id)]);
      showToast(`Failed to delete ${cartSnapshot.id}: ${err?.message ?? "please retry"}.`);
    });
  };

  const exportCartsCsv = () => {
    const exportConverted = filteredAbandonedCarts.filter((c) => c.status === "Converted").length;
    const exportLost = filteredAbandonedCarts.filter((c) => ["No response", "Not interested"].includes(c.status)).length;
    const exportRate = filteredAbandonedCarts.length === 0
      ? 0
      : Math.round((exportConverted / filteredAbandonedCarts.length) * 100);
    const rows = [
      ["Abandoned Carts Report"],
      ["Period", cartsPeriod === "Custom" && cartsDateRange.start && cartsDateRange.end ? `${cartsDateRange.start} to ${cartsDateRange.end}` : cartsPeriod],
      ["Currency", selectedCurrency.label],
      ["Search", cartSearch || "All"],
      ["Status", cartStatus],
      ["Product Filter", cartProductIds.size === 0 ? "All Products" : products.filter(p => cartProductIds.has(p.id)).map(p => p.name).join(", ")],
      ["Total Captured", String(filteredAbandonedCarts.length)],
      ["Converted", String(exportConverted)],
      ["Lost", String(exportLost)],
      ["Conversion Rate", `${exportRate}%`],
      [],
      ["Cart ID", "Customer", "Phone", "Product", "Package", "Amount", "Status", "Source", "Rep", "Created", "Last Activity"],
      ...filteredAbandonedCarts.map((cart) => [
        cart.id,
        cart.customer,
        cart.phone,
        cart.productName,
        cart.packageName,
        formatProductMoney(cart.amount, cart.currency),
        cart.status,
        cart.source,
        users.find((u) => u.id === cart.assignedRepId)?.name ?? "Unassigned",
        cart.createdAt,
        cart.lastActivity
      ])
    ];
    const csv = rows
      .map((row) => row.map((cell) => `"${String(cell).replace(/"/g, '""')}"`).join(","))
      .join("\n");
    const url = URL.createObjectURL(new Blob([csv], { type: "text/csv;charset=utf-8" }));
    const link = document.createElement("a");
    link.href = url;
    link.download = `abandoned-carts-${new Date().toISOString().slice(0, 10)}.csv`;
    document.body.appendChild(link);
    link.click();
    link.remove();
    URL.revokeObjectURL(url);
    showToast("Abandoned carts exported as CSV.");
  };

