  const convertSelectedCart = async () => {
    if (!selectedCart) {
      return;
    }

    const draftOrder: Omit<TrackedOrder, "id"> = {
      productId: selectedCart.productId,
      packageId: selectedCart.packageId,
      customer: selectedCart.customer,
      phone: selectedCart.phone,
      whatsapp: selectedCart.whatsapp,
      email: selectedCart.email,
      city: selectedCart.city,
      state: selectedCart.state,
      productName: selectedCart.productName,
      packageName: selectedCart.packageName,
      quantity: products.find((product) => product.id === selectedCart.productId)?.packages.find((item) => item.id === selectedCart.packageId)?.quantity ?? 1,
      amount: selectedCart.amount,
      currency: selectedCart.currency,
      utmSource: selectedCart.source.toLowerCase(),
      utmCampaign: "cart_recovery",
      source: selectedCart.source,
      status: "New",
      response: "Converted from abandoned cart",
      location: orderLocationFromFields(selectedCart.city ?? "", selectedCart.state ?? ""),
      assignedRepId: selectedCart.assignedRepId ?? repForNewRecord(),
      createdAt: nowIso(),
      date: displayDateFromKey(todayKey()),
      notes: [{ id: makeNoteId(), text: `Converted from ${selectedCart.id}.`, by: ownerName, date: nowIso() }]
    };
    const cartSnapshot = selectedCart;
    let orderId = "";
    try {
      const saved = await ordersApi.create({ ...draftOrder, sourceCartId: selectedCart.id });
      const order: TrackedOrder = {
        ...draftOrder,
        id: saved.id,
        assignedRepId: saved.assignedRepId ?? draftOrder.assignedRepId,
        createdAt: saved.createdAt ?? draftOrder.createdAt,
        date: saved.date ?? draftOrder.date,
        location: saved.location ?? draftOrder.location
      };
      orderId = order.id;
      setTrackedOrders((value) => [order, ...value]);
      setAbandonedCarts((value) => value.map((cart) => (cart.id === selectedCart.id ? { ...cart, status: "Converted", lastActivity: new Date().toISOString() } : cart)));
      closeModal();
      showToast(`${selectedCart.id} converted to ${order.id}.`);
    } catch (err: any) {
      showToast(`Failed to convert ${cartSnapshot.id}: ${err?.message ?? "please retry"}.`);
      return;
    }

    // Mark the cart as Converted on the server too so it doesn't keep
    // showing up as Open Abandoned for other admins.
    cartsApi.update(selectedCart.id, { status: "Converted" }).catch((err: any) => {
      setAbandonedCarts((value) => value.map((cart) => cart.id === cartSnapshot.id ? cartSnapshot : cart));
      showToast(`Cart status not synced: ${err?.message ?? "please retry"}.`);
    });

    // Conversion-specific notification (in addition to the backend's
    // order_new) — captures the cart→order link with the cart ID surfaced.
    pushSystemNotification({
      type: "info",
      title: "Cart Converted",
      message: `${selectedCart.id} converted to ${orderId} — ${draftOrder.customer} (${draftOrder.productName})`,
      orderId,
      link: `/dashboard/admin/orders/${orderId}`
    });
  };

